using System;

namespace Demo
{
    /// <summary>
    /// Provides helper routines for generating greeting text.
    /// </summary>
    public class Greeter
    {
        /// <summary>
        /// Creates a greeting for the specified person.
        /// </summary>
        /// <param name="name">The person's name. Must be non-null and non-empty.</param>
        /// <returns>A greeting with the name rendered in uppercase.</returns>
        /// <exception cref="ArgumentNullException">Thrown when <paramref name="name"/> is null.</exception>
        /// <exception cref="ArgumentException">Thrown when <paramref name="name"/> is empty or whitespace.</exception>
        public string Greet(string name)
        {
            ArgumentNullException.ThrowIfNull(name, nameof(name));
            if (string.IsNullOrWhiteSpace(name))
            {
                throw new ArgumentException("Name cannot be whitespace.", nameof(name));
            }

            return $"Hello, {name.Trim().ToUpperInvariant()}";
        }
    }
}
